import{_ as a,c as t,o as i,ae as o}from"./chunks/framework.D4x4JNJ3.js";const p=JSON.parse('{"title":"Changelog v2026.2.x","description":"","frontmatter":{"title":"Changelog v2026.2.x"},"headers":[],"relativePath":"en/changelog/v2026.2.x.md","filePath":"en/changelog/v2026.2.x.md","lastUpdated":1772161383000}'),n={name:"en/changelog/v2026.2.x.md"};function l(s,e,r,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="mogan-stem-v2026-2-x-changelog" tabindex="-1">Mogan STEM v2026.2.x Changelog <a class="header-anchor" href="#mogan-stem-v2026-2-x-changelog" aria-label="Permalink to “Mogan STEM v2026.2.x Changelog”">​</a></h1><blockquote><p>Note: Liii STEM is the commercial edition of Mogan STEM. It provides value-added features on top of the open-source version, such as account login and AI. For more details, see Liii STEM: <a href="https://liiistem.com/docs/changelog-v2026.1.x.html" target="_blank" rel="">v2026.1.x</a></p></blockquote><h2 id="⭐️-new-features-highlights" tabindex="-1">⭐️ New Features &amp; Highlights <a class="header-anchor" href="#⭐️-new-features-highlights" aria-label="Permalink to “⭐️ New Features &amp; Highlights”">​</a></h2><ol><li><strong>Three-line tables</strong>: Added a three-line table type (<code>Insert</code> -&gt; <code>Table</code> -&gt; <code>Three-line table</code>) for more academic-style tables.</li><li><strong>Improved LaTeX import</strong>: Fixed layout misalignment when importing complex structures such as piecewise functions.</li><li><strong>Better image interaction</strong>: Images can now be zoomed with the mouse.</li><li><strong>More symbols</strong>: Added a LEGO symbol for <code>/ /</code>.</li><li><strong>More stable Tab Cycling</strong>: Fixed the Tab Cycling popup positioning reference under zoom/layout changes.</li><li><strong>More consistent import/export on Windows</strong>: Prefer the bundled Pandoc to reduce environment-related issues.</li><li><strong>Plugin stability</strong>: Fixed Python plugin errors caused by <code>sympy.symbol</code>; removed an incomplete Octave plugin that could freeze the app.</li><li><strong>UX polish</strong>: Tweaked the “Open PDF” dialog; removed the extra “Untitled file” that could appear in the title bar when opening existing files.</li></ol><h2 id="🌟-summary" tabindex="-1">🌟 Summary <a class="header-anchor" href="#🌟-summary" aria-label="Permalink to “🌟 Summary”">​</a></h2><p>Mogan 2.0 (v2026.2.x) focuses on <strong>tables &amp; import/export</strong> and <strong>plugin stability</strong>: three-line tables, better LaTeX (piecewise) import, and a more consistent Pandoc setup on Windows. It also fixes/cleans up plugins that impacted stability and polishes Tab Cycling and a few UI details. Liii STEM builds on top of this with value-added features such as AI.</p><h2 id="🔧-release-notes" tabindex="-1">🔧 Release Notes <a class="header-anchor" href="#🔧-release-notes" aria-label="Permalink to “🔧 Release Notes”">​</a></h2><h3 id="mogan-stem-v2026-2-0-2026-02-13" tabindex="-1">Mogan STEM v2026.2.0 (2026/02/13) <a class="header-anchor" href="#mogan-stem-v2026-2-0-2026-02-13" aria-label="Permalink to “Mogan STEM v2026.2.0 (2026/02/13)”">​</a></h3><ol><li>(Liii STEM) <strong>AI</strong>: Added GLM-4.6V and Kimi-K2.5 models.</li><li>Added three-line tables (<code>Insert</code> -&gt; <code>Table</code> -&gt; <code>Three-line table</code>).</li><li>Images can now be zoomed with the mouse.</li><li>Added a LEGO symbol for <code>/ /</code>.</li><li>Fixed Tab Cycling popup positioning reference.</li><li>Fixed layout issues when importing piecewise functions from LaTeX.</li><li>Tweaked the “Open PDF” dialog UI.</li><li>On Windows, prefer the bundled Pandoc.</li><li>Fixed Python plugin errors caused by <code>sympy.symbol</code>.</li><li>Removed an incomplete Octave plugin that could freeze the app.</li><li>When opening existing files, removed the extra “Untitled file” shown in the title bar.</li></ol><h2 id="👏-join-us" tabindex="-1">👏 Join Us <a class="header-anchor" href="#👏-join-us" aria-label="Permalink to “👏 Join Us”">​</a></h2><ul><li>Mogan STEM Official Website: <a href="https://mogan.app/" target="_blank" rel="">https://mogan.app/</a></li><li>Mogan Community QQ Group: <a href="https://qun.qq.com/universal-share/share?ac=1&amp;authKey=NoxIHFT4nzWfHJnqGNQygmXt%2FhpydluCE%2FcF1qMzu1BHpNNjv7ZGZxWwS0fGx32Y&amp;busi_data=eyJncm91cENvZGUiOiI5MzQ0NTY5NzEiLCJ0b2tlbiI6InpOMGxCaHIvdEtyM1V1d0VGYlpTQThZZ2NDODQxUjU1dWdBZEF5cG9MUHptN3R6Q1NXenNaWVluOVpjOTd3VHAiLCJ1aW4iOiI3ODUyNTEzMjIifQ%3D%3D&amp;data=n9XWNwOuQOWPbezHFAHZS24nvSli9BNzrLjrfFr_JWfStSboc6G5DZwBXWzZDqXc5A29OptCvKgtVjZ1Gwmu1A&amp;svctype=4&amp;tempid=h5_group_info" target="_blank" rel="">934456971</a></li><li>Discord Group: <a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="">https://discord.gg/Q7xARnAf8t</a></li></ul>',11)])])}const m=a(n,[["render",l]]);export{p as __pageData,m as default};
